Here are some JavaScript code examples for generating random numbers without repetition:

1. **Using an array and sorting:**
```javascript
function getRandomNumbers(count, max) {
    let numbers = Array.from({length: max}, (_, i) => i + 1);
    for (let i = numbers.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [numbers[i], numbers[j]] = [numbers[j], numbers[i]];
    }
    return numbers.slice(0, count);
}

console.log(getRandomNumbers(5, 10)); // Example: [1, 3, 7, 9, 2]
```

2. **Using a Set and a while loop:**
```javascript
function getRandomNumbers(count, max) {
    const numbers = new Set();
    while (numbers.size < count) {
        const num = Math.floor(Math.random() * max) + 1;
        numbers.add(num);
    }
    return Array.from(numbers);
}

console.log(getRandomNumbers(5, 10)); // Example: [3, 7, 1, 9, 5]
```

3. **Using Fisher-Yates shuffle algorithm:**
```javascript
function getRandomNumbers(count, max) {
    const numbers = Array.from({length: max}, (_, i) => i + 1);
    for (let i = numbers.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [numbers[i], numbers[j]] = [numbers[j], numbers[i]];
    }
    return numbers.slice(0, count);
}

console.log(getRandomNumbers(5, 10)); // Example: [1, 3, 7, 9, 2]
```

These examples demonstrate how to generate random numbers without repetition using different approaches in JavaScript.

